import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface EnergyData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    currentConsumption: {
      value: number;
      unit: string;
    };
    dailyCost: {
      value: number;
      currency: string;
    };
    usageTrend: number[];
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const energyData = response.data as EnergyData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2E2E2E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Current Consumption
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: energyData.meta.primaryColor }}>
              {energyData.data.currentConsumption.value} {energyData.data.currentConsumption.unit}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Daily Cost: {energyData.data.dailyCost.currency} {energyData.data.dailyCost.value.toFixed(2)}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: energyData.data.usageTrend,
                  color: energyData.meta.accentColor,
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: energyData.data.usageTrend.map((_, index) => index),
                  id: 'days',
                  hide: true,
                },
              ]}
              yAxis={[{ id: 'consumption' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="consumption"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
